CREATE TYPE NoteType AS (
	PUBLIC VARCHAR,
	PRIVATE VARCHAR,
	OPINION VARCHAR,
	EXPERT_OPINION VARCHAR
);


CREATE TABLE IF NOT EXISTS "User" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"email" VARCHAR(255) NOT NULL UNIQUE,
	"phone" VARCHAR(255),
	"firstName" VARCHAR(255),
	"lastName" VARCHAR(255),
	"type" VARCHAR(255),
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "Attachment" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"noteId" INTEGER NOT NULL,
	"fileUrl" VARCHAR(255) NOT NULL,
	"fileName" VARCHAR(255) NOT NULL,
	"createdAt" TIMESTAMP NOT NULL,
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "Note" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"content" VARCHAR(255) NOT NULL,
	"type" NOTETYPE NOT NULL,
	"createdAt" TIMESTAMP NOT NULL,
	"authorId" INTEGER NOT NULL,
	"orderId" INTEGER NOT NULL,
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "Order" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"orderNumber" VARCHAR(255),
	"externalNumber" VARCHAR(255),
	"caseSignature" VARCHAR(255),
	"damageDate" TIMESTAMP,
	"createdAt" TIMESTAMP NOT NULL,
	"updatedAt" TIMESTAMP NOT NULL,
	"vehicleId" INTEGER,
	"clientId" INTEGER,
	"expertId" INTEGER,
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "Party" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"firstName" VARCHAR(255),
	"lastName" VARCHAR(255),
	"phone" VARCHAR(255),
	"email" VARCHAR(255),
	"isExpert" BOOLEAN NOT NULL,
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "Vehicle" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"brand" VARCHAR(255),
	"model" VARCHAR(255),
	"licensePlate" VARCHAR(255),
	"vin" VARCHAR(255),
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "OrderStatuses" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"technicalName" VARCHAR(255) NOT NULL,
	"displayName" VARCHAR(255) NOT NULL,
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "OrdersAssignedUsers" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"orderStatusId" INTEGER NOT NULL,
	"orderId" INTEGER NOT NULL,
	"userId" INTEGER NOT NULL,
	"assignedAt" TIMESTAMP NOT NULL,
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "OrderChangeLogs" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"order_id" INTEGER NOT NULL,
	"user_id" INTEGER NOT NULL,
	"changed_at" TIMESTAMP NOT NULL,
	"description" VARCHAR(255),
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "BasicData" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"report_id" INTEGER,
	"brand" VARCHAR(255),
	"model" VARCHAR(255),
	"vin" VARCHAR(255),
	"registration_number" VARCHAR(255),
	"production_year" INTEGER,
	"created_at" TIMESTAMP,
	"updated_at" TIMESTAMP,
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "Reports" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"report_number" VARCHAR(255),
	"user_id" INTEGER,
	"order_id" INTEGER,
	"created_at" TIMESTAMP,
	"updated_at" TIMESTAMP,
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "report_attachments" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"report_id" INTEGER,
	"url" VARCHAR(255),
	"comment" VARCHAR(255),
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "report_fields_config" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"label" VARCHAR(255),
	"field_type" VARCHAR(255),
	"example_value" VARCHAR(255),
	"created_at" TIMESTAMP,
	"updated_at" TIMESTAMP,
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "report_dynamic_values" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"report_id" INTEGER,
	"field_id" INTEGER,
	"value" VARCHAR(255),
	"created_at" TIMESTAMP,
	"updated_at" TIMESTAMP,
	PRIMARY KEY("id")
);



ALTER TABLE "Order"
ADD FOREIGN KEY("vehicleId") REFERENCES "Vehicle"("id")
ON UPDATE NO ACTION ON DELETE NO ACTION;
